/**
 * SessionStore persistence logic tests backed by the FsLike seam.
 *
 * Real filesystem fidelity for fd write + rename semantics, no stray .tmp files,
 * and backup recovery after corrupt primary is pinned in
 * tests2/integration/session-store-real-fs.test.ts.
 */
import { beforeEach, describe, it } from "vitest";
import assert from "node:assert/strict";
import path from "node:path";
import type { PathLike, PathOrFileDescriptor, WriteFileOptions } from "node:fs";
import { SessionStore, type PersistedSession } from "../../src/server/agent/session-store.ts";
import { createMemFs, type MemFs } from "../harness/mem-fs.js";

type SessionStoreMemFs = MemFs & {
	openSync(file: PathLike, flags: string): number;
	fsyncSync(fd: number): void;
	closeSync(fd: number): void;
};

function createSessionStoreMemFs(): SessionStoreMemFs {
	const memfs = createMemFs() as SessionStoreMemFs;
	const baseWriteFileSync = memfs.writeFileSync.bind(memfs) as (file: PathLike, data: string | NodeJS.ArrayBufferView, options?: WriteFileOptions) => void;
	const fdPaths = new Map<number, string>();
	let nextFd = 100;

	memfs.openSync = (file: PathLike, _flags: string): number => {
		const fd = nextFd++;
		const resolved = path.resolve(String(file));
		fdPaths.set(fd, resolved);
		baseWriteFileSync(resolved, "", "utf-8");
		return fd;
	};
	memfs.writeFileSync = ((file: PathOrFileDescriptor, data: string | NodeJS.ArrayBufferView, options?: WriteFileOptions) => {
		if (typeof file === "number") {
			const target = fdPaths.get(file);
			if (!target) throw Object.assign(new Error(`EBADF: bad file descriptor, write '${file}'`), { code: "EBADF" });
			baseWriteFileSync(target, data, options);
			return;
		}
		baseWriteFileSync(file, data, options);
	}) as typeof memfs.writeFileSync;
	memfs.fsyncSync = () => { /* no-op for in-memory unit tests */ };
	memfs.closeSync = (fd: number) => {
		if (!fdPaths.delete(fd)) throw Object.assign(new Error(`EBADF: bad file descriptor, close '${fd}'`), { code: "EBADF" });
	};
	return memfs;
}

type FingerprintTrackingFs = SessionStoreMemFs & {
	primaryReads: number;
	failPrimaryStat: boolean;
	externalWrite(data: string): void;
	resetPrimaryReads(): void;
};

function createFingerprintTrackingFs(storeFile: string): FingerprintTrackingFs {
	const memfs = createSessionStoreMemFs() as FingerprintTrackingFs;
	const primary = path.resolve(storeFile);
	const baseReadFileSync = memfs.readFileSync.bind(memfs);
	const baseWriteFileSync = memfs.writeFileSync.bind(memfs);
	const baseStatSync = memfs.statSync.bind(memfs);
	const baseRenameSync = memfs.renameSync.bind(memfs);
	let fingerprintVersion = 1;

	memfs.primaryReads = 0;
	memfs.failPrimaryStat = false;
	memfs.resetPrimaryReads = () => { memfs.primaryReads = 0; };
	memfs.externalWrite = (data: string) => {
		baseWriteFileSync(primary, data, "utf-8");
		fingerprintVersion++;
	};
	memfs.readFileSync = ((file: PathLike | number, ...args: unknown[]) => {
		if (typeof file !== "number" && path.resolve(String(file)) === primary) memfs.primaryReads++;
		return (baseReadFileSync as (...callArgs: unknown[]) => unknown)(file, ...args);
	}) as typeof memfs.readFileSync;
	(memfs as { statSync: typeof memfs.statSync }).statSync = ((file: PathLike, ...args: unknown[]) => {
		const isPrimary = path.resolve(String(file)) === primary;
		if (isPrimary && memfs.failPrimaryStat) throw Object.assign(new Error("injected stat failure"), { code: "EIO" });
		const stat = (baseStatSync as (...callArgs: unknown[]) => import("node:fs").Stats)(file, ...args);
		return isPrimary
			? { ...stat, mtimeMs: fingerprintVersion, ctimeMs: fingerprintVersion }
			: stat;
	}) as typeof memfs.statSync;
	memfs.renameSync = ((from: PathLike, to: PathLike) => {
		baseRenameSync(from, to);
		if (path.resolve(String(to)) === primary) fingerprintVersion++;
	}) as typeof memfs.renameSync;
	return memfs;
}

const stateDir = path.resolve("/memfs/session-store-atomic/state");
const STORE_FILE = path.join(stateDir, "sessions.json");
const BAK_1 = `${STORE_FILE}.bak.1`;
const TMP = `${STORE_FILE}.tmp`;

let memfs: SessionStoreMemFs;

function makeSession(id: string): PersistedSession {
	return {
		id,
		title: `Session ${id}`,
		cwd: "/tmp/test",
		agentSessionFile: `/tmp/test/${id}.jsonl`,
		createdAt: Date.now(),
		lastActivity: Date.now(),
	};
}

describe("SessionStore atomic write", () => {
	beforeEach(() => {
		memfs = createSessionStoreMemFs();
		memfs.mkdirSync(stateDir, { recursive: true });
	});

	it("writes compact v2 JSON with monotonically increasing epoch and reloads identically", () => {
		const store = new SessionStore(stateDir, memfs);
		store.put(makeSession("s1"));
		store.put(makeSession("s2"));
		store.put(makeSession("s3"));
		store.flush();

		const raw = memfs.readFileSync(STORE_FILE, "utf-8");
		const parsed = JSON.parse(raw);
		assert.equal(raw, JSON.stringify(parsed), "sessions.json must contain no pretty-print whitespace");
		assert.equal(parsed.version, 2);
		assert.equal(typeof parsed.epoch, "number");
		assert.equal(parsed.epoch, 3, "three put()s ⇒ epoch=3");
		assert.equal(parsed.sessions.length, 3);
		const ids = parsed.sessions.map((s: PersistedSession) => s.id).sort();
		assert.deepEqual(ids, ["s1", "s2", "s3"]);

		const restored = new SessionStore(stateDir, memfs);
		assert.equal(restored.getLoadedEpoch(), parsed.epoch);
		assert.deepEqual(restored.getAll(), parsed.sessions);
	});

	it("fully validates the first save, then skips reads while its own fingerprint is unchanged", () => {
		const fs = createFingerprintTrackingFs(STORE_FILE);
		fs.mkdirSync(stateDir, { recursive: true });
		fs.externalWrite(JSON.stringify({ version: 2, epoch: 7, sessions: [makeSession("seed")] }, null, 2));
		const store = new SessionStore(stateDir, fs);
		fs.resetPrimaryReads();

		store.put(makeSession("s1"));
		assert.equal(fs.primaryReads, 1, "first save after load must still read and parse the disk epoch");

		fs.resetPrimaryReads();
		store.put(makeSession("s2"));
		assert.equal(fs.primaryReads, 0, "unchanged post-own-write fingerprint should reuse the known epoch");
		assert.equal(store.getWrittenEpoch(), 9);
	});

	it("falls back to a full epoch read after an external rewrite or stat failure", () => {
		const fs = createFingerprintTrackingFs(STORE_FILE);
		fs.mkdirSync(stateDir, { recursive: true });
		const store = new SessionStore(stateDir, fs);
		store.put(makeSession("s1"));

		fs.externalWrite(JSON.stringify({ version: 2, epoch: 40, sessions: [makeSession("external")] }));
		fs.resetPrimaryReads();
		store.put(makeSession("s2"));
		assert.equal(fs.primaryReads, 1, "changed fingerprint must force a full read and parse");
		assert.equal(store.getWrittenEpoch(), 41, "existing epoch progression remains authoritative");

		fs.failPrimaryStat = true;
		fs.resetPrimaryReads();
		store.put(makeSession("s3"));
		assert.equal(fs.primaryReads, 1, "stat errors must disable the fast path and fully validate");
		assert.equal(store.getWrittenEpoch(), 42);
	});

	it("does not leave a .tmp file behind after a successful save", () => {
		const store = new SessionStore(stateDir, memfs);
		store.put(makeSession("s1"));
		store.flush();
		assert.ok(memfs.existsSync(STORE_FILE));
		assert.ok(!memfs.existsSync(TMP), "no stray .tmp after successful save");
	});

	it("rotates a backup before each save (.bak.1 has prior payload)", () => {
		const store = new SessionStore(stateDir, memfs);
		store.put(makeSession("s1"));   // epoch 1
		store.put(makeSession("s2"));   // epoch 2 — at this point .bak.1 should hold epoch 1
		store.flush();

		assert.ok(memfs.existsSync(BAK_1), ".bak.1 created on the second save");
		const bakParsed = JSON.parse(memfs.readFileSync(BAK_1, "utf-8"));
		assert.equal(bakParsed.epoch, 1);
		assert.equal(bakParsed.sessions.length, 1);
		assert.equal(bakParsed.sessions[0].id, "s1");

		const primaryParsed = JSON.parse(memfs.readFileSync(STORE_FILE, "utf-8"));
		assert.equal(primaryParsed.epoch, 2);
		assert.equal(primaryParsed.sessions.length, 2);
	});

	it("recovers from .bak.1 when sessions.json is corrupt", () => {
		// Seed: write some data, then corrupt the primary.
		const store1 = new SessionStore(stateDir, memfs);
		store1.put(makeSession("s1"));
		store1.put(makeSession("s2"));
		store1.put(makeSession("s3"));
		store1.flush();

		assert.ok(memfs.existsSync(BAK_1), "expected .bak.1 to exist");
		const bakBefore = memfs.readFileSync(BAK_1, "utf-8");
		const bakBeforeParsed = JSON.parse(bakBefore);

		// Simulate a torn write: truncate the primary to garbage. The .bak.1
		// snapshot represents the state after an earlier save (s1+s2, epoch 2),
		// which is the most recent consistent on-disk state we can recover to.
		memfs.writeFileSync(STORE_FILE, "{ this is not val", "utf-8");

		// Capture warns
		const warns: string[] = [];
		const origWarn = console.warn;
		console.warn = (...args: unknown[]) => { warns.push(args.map(String).join(" ")); };
		try {
			const store2 = new SessionStore(stateDir, memfs);
			const all = store2.getAll();
			assert.equal(all.length, bakBeforeParsed.sessions.length, "loaded all sessions from .bak.1");
			const ids = all.map(s => s.id).sort();
			assert.deepEqual(ids, bakBeforeParsed.sessions.map((s: PersistedSession) => s.id).sort());
		} finally {
			console.warn = origWarn;
		}

		const sawBackupWarn = warns.some(w => /Loaded from backup/.test(w) || /Failed to parse/.test(w));
		assert.ok(sawBackupWarn, `expected a backup-recovery warn line, got: ${warns.join("\n")}`);
	});

	it("survives a kill-mid-write (truncated .tmp) — primary remains recoverable", () => {
		// First save lands cleanly.
		const store1 = new SessionStore(stateDir, memfs);
		store1.put(makeSession("s1"));
		store1.put(makeSession("s2"));
		store1.flush();
		const primaryBefore = memfs.readFileSync(STORE_FILE, "utf-8");

		// Monkey-patch writeFileSync(fd) to truncate the next tmp write to 100
		// bytes — emulating a kill-9 between writeFileSync and rename.
		const origWriteFileSync = memfs.writeFileSync;
		memfs.writeFileSync = ((
			file: PathOrFileDescriptor,
			data: string | NodeJS.ArrayBufferView,
			options?: WriteFileOptions,
		) => {
			if (typeof file === "number" && typeof data === "string" && data.length > 100) {
				return origWriteFileSync(file, data.slice(0, 100), options);
			}
			return origWriteFileSync(file, data, options);
		}) as typeof memfs.writeFileSync;

		try {
			// Add a third session — the save will produce a truncated .tmp, but the
			// previous payload is preserved in .bak.1 for restart recovery.
			store1.put(makeSession("s3"));
			store1.flush();
		} finally {
			memfs.writeFileSync = origWriteFileSync;
		}

		const warns: string[] = [];
		const origWarn = console.warn;
		console.warn = (...args: unknown[]) => { warns.push(args.map(String).join(" ")); };
		try {
			const store2 = new SessionStore(stateDir, memfs);
			const ids = store2.getAll().map(s => s.id).sort();
			assert.ok(ids.includes("s1") && ids.includes("s2"), `expected s1+s2 to survive, got ${ids.join(",")}`);
		} finally {
			console.warn = origWarn;
		}

		// Sanity: primaryBefore was a healthy JSON before the torn write.
		assert.doesNotThrow(() => JSON.parse(primaryBefore));
	});
});
